"""Convert parsed IL instructions to IEC 61131-3 ST code."""
import re
from .parser import ILInstruction
from .mapping import (
    convert_address, get_comment, timer_preset_to_iec,
    hex_device_to_decimal, sanitize_program_name,
)
from .instructions import (
    LOAD_INSTRUCTIONS, AND_INSTRUCTIONS, OR_INSTRUCTIONS,
    RISING_EDGE, FALLING_EDGE,
)


class STConverter:
    """Converts a list of IL instructions to ST code."""

    def __init__(self, program_name: str):
        self.program_name = sanitize_program_name(program_name)
        self.output_lines = []
        self.var_declarations = {}  # name -> type
        self.trig_instances = {}    # key -> instance name
        self.ton_instances = {}     # raw_timer_addr -> instance name
        self.ton_q_alias = {}       # converted_timer_addr -> inst_name.Q
        self.mpush_counter = 0
        self.expr_stack = []
        self.mpush_stack = []
        self.current_rung = -1
        self._needs_tmpUdint = False
        self._needs_tmpTime = False
        self._var_comments = {}  # name -> comment for CSV

    def convert(self, instructions: list[ILInstruction]) -> str:
        """Convert IL instruction list to ST program string."""
        self._first_pass(instructions)
        self._second_pass(instructions)
        return self._build_output()

    def _first_pass(self, instructions: list[ILInstruction]):
        """Scan for R_TRIG/F_TRIG and TON instances needed."""
        for inst in instructions:
            if inst.opcode in RISING_EDGE and inst.operands:
                addr = inst.operands[0]
                conv = convert_address(addr)
                name = f'RT_{_safe_name(conv)}'
                # Use converted address as key to avoid duplicates
                # (e.g., LOADP M0000A and ORP M00010 both → M00016)
                self.trig_instances[f'R_{conv}'] = name
                self.var_declarations[name] = 'R_TRIG'
            elif inst.opcode in FALLING_EDGE and inst.operands:
                addr = inst.operands[0]
                conv = convert_address(addr)
                name = f'FT_{_safe_name(conv)}'
                self.trig_instances[f'F_{conv}'] = name
                self.var_declarations[name] = 'F_TRIG'
            elif inst.opcode == 'TON' and inst.operands:
                raw_addr = inst.operands[0]
                conv = convert_address(raw_addr)
                name = f'TON_{_safe_name(conv)}'
                self.ton_instances[raw_addr] = name
                self.ton_q_alias[conv] = f'{name}.Q'
                self.var_declarations[name] = 'TON'

    def _second_pass(self, instructions: list[ILInstruction]):
        """Generate ST code from instructions."""
        self.expr_stack = []
        self.mpush_stack = []
        self.mpush_counter = 0

        # Emit R_TRIG/F_TRIG update calls at program start
        self._emit('// Edge detection update')
        for key, name in sorted(self.trig_instances.items()):
            addr = key[2:]  # address after "R_" or "F_" — already converted
            addr = self._resolve_timer(addr)  # T0083 → TON_T0083.Q
            self._emit(f'{name}(CLK := {addr});')
        self._emit('')

        for inst in instructions:
            if inst.rung != self.current_rung:
                self.current_rung = inst.rung
                self._emit(f'\n// --- Rung {inst.rung} ---')
            self._convert_instruction(inst)

    def _convert_instruction(self, inst: ILInstruction):
        """Convert single instruction to ST."""
        op = inst.opcode
        ops = [convert_address(o) for o in inst.operands]

        # --- LOAD family ---
        if op in LOAD_INSTRUCTIONS:
            expr = self._make_load_expr(op, ops)
            self.expr_stack.append(expr)

        # --- AND family ---
        elif op in AND_INSTRUCTIONS:
            if not self.expr_stack:
                return
            right = self._make_condition_expr(op, ops)
            self.expr_stack[-1] = f'({self.expr_stack[-1]}) AND ({right})'

        # --- OR family ---
        elif op in OR_INSTRUCTIONS:
            if not self.expr_stack:
                return
            right = self._make_condition_expr(op, ops)
            self.expr_stack[-1] = f'({self.expr_stack[-1]}) OR ({right})'

        # --- Combinators ---
        elif op == 'AND LOAD':
            if len(self.expr_stack) >= 2:
                b, a = self.expr_stack.pop(), self.expr_stack.pop()
                self.expr_stack.append(f'({a}) AND ({b})')
        elif op == 'OR LOAD':
            if len(self.expr_stack) >= 2:
                b, a = self.expr_stack.pop(), self.expr_stack.pop()
                self.expr_stack.append(f'({a}) OR ({b})')

        # --- NOT ---
        elif op == 'NOT':
            if self.expr_stack:
                self.expr_stack[-1] = f'NOT ({self.expr_stack[-1]})'

        # --- MPUSH / MLOAD / MPOP ---
        elif op == 'MPUSH':
            self.mpush_counter += 1
            var = f'_mpush_{self.mpush_counter}'
            self.var_declarations[var] = 'BOOL'
            cond = self.expr_stack[-1] if self.expr_stack else 'FALSE'
            self._emit(f'{var} := {cond};')
            self.mpush_stack.append(var)
        elif op == 'MLOAD':
            if self.mpush_stack:
                self.expr_stack.append(self.mpush_stack[-1])
        elif op == 'MPOP':
            if self.mpush_stack:
                self.expr_stack.append(self.mpush_stack.pop())

        # --- Output ---
        elif op == 'OUT':
            self._emit_output(ops[0], ':=', self._current_cond())
        elif op == 'SET':
            cond = self._current_cond()
            self._emit(f'IF {cond} THEN')
            self._emit(f'    {ops[0]} := TRUE;')
            self._emit('END_IF;')
        elif op == 'RST':
            cond = self._current_cond()
            self._emit(f'IF {cond} THEN')
            self._emit(f'    {ops[0]} := FALSE;')
            self._emit('END_IF;')

        # --- TON (no T device assignment — use .Q inline) ---
        elif op == 'TON':
            self._convert_ton(ops, inst.operands)

        # --- MOV / MOVP ---
        elif op in ('MOV', 'DMOV'):
            cond = self._current_cond()
            src = self._resolve_timer_value(ops[0])
            self._emit(f'IF {cond} THEN')
            self._emit(f'    {ops[1]} := {src};')
            self._emit('END_IF;')
        elif op in ('MOVP', 'DMOVP'):
            cond = self._current_cond()
            src = self._resolve_timer_value(ops[0])
            self._emit(f'IF {cond} THEN  // pulse')
            self._emit(f'    {ops[1]} := {src};')
            self._emit('END_IF;')

        # --- FMOV (fill) — expand to individual assignments ---
        elif op == 'FMOV':
            self._expand_fmov(ops, inst.operands)

        # --- GMOV / GMOVP (block copy) — expand to individual assignments ---
        elif op in ('GMOV', 'GMOVP'):
            self._expand_gmov(ops, inst.operands)

        # --- Arithmetic (pulse) ---
        elif op == 'ADDP':
            self._emit_arith(ops, '+')
        elif op == 'MULP':
            self._emit_arith(ops, '*')
        elif op == 'DIVP':
            self._emit_arith(ops, '/')
        elif op in ('INCP', 'DINCP'):
            cond = self._current_cond()
            self._emit(f'IF {cond} THEN  // pulse')
            if ops[0].startswith('%MW'):
                self._emit(f'    {ops[0]} := INT_TO_WORD(WORD_TO_INT({ops[0]}) + 1);')
            elif ops[0].startswith('%MD'):
                self._emit(f'    {ops[0]} := DINT_TO_DWORD(DWORD_TO_DINT({ops[0]}) + 1);')
            else:
                self._emit(f'    {ops[0]} := {ops[0]} + 1;')
            self._emit('END_IF;')

        # --- GET: U device read → %UW direct access (already converted) ---
        elif op == 'GET':
            # ops[2] is dest (D device → %MW), ops[0] is slot, ops[1] is register
            # In XEC, U device is read via %UW directly, so GET becomes:
            # dest := %UW_addr; (the %UW addr is derived from ops[0] and ops[1])
            cond = self._current_cond()
            self._emit(f'IF {cond} THEN')
            self._emit(f'    {ops[2]} := {ops[0]};  // GET: read special module')
            self._emit('END_IF;')
        elif op == 'PUTP':
            # PUTP(slot_reg, value, ...) → %UW direct write
            cond = self._current_cond()
            self._emit(f'IF {cond} THEN  // PUTP → direct %UW write')
            self._emit(f'    {ops[0]} := {ops[2]};')
            self._emit('END_IF;')
        elif op == 'ORG':
            self._emit(f'// ORG slot={ops[0]} ch={ops[1]}')

        # --- DECO — positional ---
        elif op == 'DECO':
            cond = self._current_cond()
            self._emit(f'IF {cond} THEN')
            self._emit(f'    DECO({ops[0]}, {ops[1]}, {ops[2]});')
            self._emit('END_IF;')

        elif op == 'END':
            pass

    def _make_load_expr(self, op: str, ops: list) -> str:
        """Build expression for LOAD-family instructions."""
        if op == 'LOAD':
            return self._resolve_timer(ops[0])
        elif op == 'LOAD NOT':
            return f'NOT {self._resolve_timer(ops[0])}'
        elif op == 'LOADP':
            return self._trig_call('R', ops[0])
        elif op == 'LOADN':
            return self._trig_call('F', ops[0])
        return self._comparison_expr(op, ops)

    def _make_condition_expr(self, op: str, ops: list) -> str:
        """Build sub-expression for AND/OR-family instructions."""
        if 'NOT' in op:
            return f'NOT {self._resolve_timer(ops[0])}'
        elif op in RISING_EDGE:
            return self._trig_call('R', ops[0])
        elif op in FALLING_EDGE:
            return self._trig_call('F', ops[0])
        elif any(c in op for c in '=<>'):
            return self._comparison_expr(op, ops)
        return self._resolve_timer(ops[0])

    def _comparison_expr(self, op: str, ops: list) -> str:
        """Build comparison expression from instruction like AND>=."""
        for prefix in ('LOADD', 'LOAD', 'ANDD', 'AND', 'ORD', 'OR'):
            if op.startswith(prefix):
                comp_op = op[len(prefix):]
                break
        else:
            comp_op = '='
        return f'{ops[0]} {comp_op} {ops[1]}'

    def _trig_call(self, kind: str, addr: str) -> str:
        """Generate R_TRIG/F_TRIG .Q reference."""
        # addr is already converted; key is also converted
        key = f'{kind}_{addr}'
        if key in self.trig_instances:
            return f'{self.trig_instances[key]}.Q'
        return f'{kind}T_{_safe_name(addr)}.Q'

    def _resolve_timer(self, addr: str) -> str:
        """Replace T device reference with TON instance .Q (BOOL context)."""
        if addr in self.ton_q_alias:
            return self.ton_q_alias[addr]
        return addr

    def _resolve_timer_value(self, addr: str) -> str:
        """Replace T device with TON .ET for value context (MOV to D device)."""
        # T device used as source in MOV → read elapsed time
        for raw_addr, inst_name in self.ton_instances.items():
            conv = convert_address(raw_addr)
            if addr == conv:
                self._needs_tmpUdint = True
                return f'UDINT_TO_WORD(TIME_TO_UDINT({inst_name}.ET) / 100)'
        return addr

    def _current_cond(self) -> str:
        return self.expr_stack[-1] if self.expr_stack else 'TRUE'

    def _convert_ton(self, ops: list, raw_ops: list):
        """Convert TON timer instruction — no T device assignment."""
        inst_name = self.ton_instances.get(raw_ops[0], f'TON_{ops[0]}')
        preset_raw = raw_ops[1] if len(raw_ops) > 1 else '0'
        pt_value = timer_preset_to_iec(raw_ops[0], preset_raw)
        cond = self._current_cond()

        # Handle dynamic preset (from D device)
        if pt_value.startswith('__DYNAMIC_PT__'):
            _, dev_addr, multiplier = pt_value.split('|')
            conv_addr = convert_address(dev_addr)
            self._needs_tmpUdint = True
            self._needs_tmpTime = True
            self._emit(f'tmpUdint := WORD_TO_UDINT({conv_addr});')
            self._emit(f'tmpUdint := tmpUdint * {multiplier};')
            self._emit(f'tmpTime := UDINT_TO_TIME(tmpUdint);')
            self._emit(f'{inst_name}(IN := {cond}, PT := tmpTime);')
        else:
            self._emit(f'{inst_name}(IN := {cond}, PT := {pt_value});')
        # No "T000x := TON.Q" — timer references resolved inline via _resolve_timer

    def _emit_arith(self, ops: list, operator: str):
        cond = self._current_cond()
        src0 = self._wrap_arith_operand(ops[0])
        src1 = self._wrap_arith_operand(ops[1])
        result_expr = f'{src0} {operator} {src1}'
        # %MW는 WORD 타입 → 산술 결과를 INT_TO_WORD로 감싸야 함
        if ops[2].startswith('%MW'):
            result_expr = f'INT_TO_WORD({result_expr})'
        elif ops[2].startswith('%MD'):
            result_expr = f'DINT_TO_DWORD({result_expr})'
        self._emit(f'IF {cond} THEN  // pulse')
        self._emit(f'    {ops[2]} := {result_expr};')
        self._emit('END_IF;')

    def _expand_fmov(self, ops: list, raw_ops: list):
        """FMOV(value, dest, count) → individual assignments."""
        cond = self._current_cond()
        try:
            count = int(raw_ops[2])
        except (ValueError, IndexError):
            count = 1
        src_val = ops[0]
        dest_addr = ops[1]
        # Extract base number from dest %MW address
        m = re.match(r'^%MW(\d+)$', dest_addr)
        if m:
            base = int(m.group(1))
            self._emit(f'IF {cond} THEN')
            for j in range(count):
                self._emit(f'    %MW{base + j} := {src_val};')
            self._emit('END_IF;')
        else:
            self._emit(f'IF {cond} THEN')
            self._emit(f'    {dest_addr} := {src_val};  // FMOV count={count}')
            self._emit('END_IF;')

    def _expand_gmov(self, ops: list, raw_ops: list):
        """GMOV(src, dest, count) → individual reverse-order assignments."""
        cond = self._current_cond()
        try:
            count = int(raw_ops[2])
        except (ValueError, IndexError):
            count = 1
        src_addr = ops[0]
        dest_addr = ops[1]
        ms = re.match(r'^%MW(\d+)$', src_addr)
        md = re.match(r'^%MW(\d+)$', dest_addr)
        if ms and md:
            src_base = int(ms.group(1))
            dst_base = int(md.group(1))
            self._emit(f'IF {cond} THEN')
            # Reverse order to handle overlapping shift correctly
            for j in range(count - 1, -1, -1):
                self._emit(f'    %MW{dst_base + j} := %MW{src_base + j};')
            self._emit('END_IF;')
        else:
            self._emit(f'IF {cond} THEN')
            self._emit(f'    // GMOV({src_addr}, {dest_addr}, {count}) - manual expansion needed')
            self._emit('END_IF;')

    def _emit_output(self, addr: str, assign: str, cond: str):
        self._emit(f'{addr} {assign} {cond};')

    def _emit(self, line: str):
        self.output_lines.append(line)

    def _build_output(self) -> str:
        """Build ST code body only (no PROGRAM/VAR wrapper).
        XG5000 manages program name and variables via GUI.
        """
        return '\n'.join(self.output_lines)

    def get_var_declarations(self) -> dict:
        """Return variable declarations for XG5000 variable table.
        Returns dict of {name: type} for user to register in XG5000 GUI.
        """
        return dict(sorted(self.var_declarations.items()))

    def build_var_csv(self) -> str:
        """Build CSV for XG5000 variable import.
        Format matches XG5000 export: 변수 종류,변수,타입,메모리 할당,초기값,리테인,사용 유무,EIP,OPC UA,HMI,설명문
        """
        # Auto-add tmpUdint/tmpTime if dynamic timer or timer ET access used
        if self._needs_tmpUdint:
            self.var_declarations['tmpUdint'] = 'UDINT'
        if self._needs_tmpTime:
            self.var_declarations['tmpTime'] = 'TIME'
        lines = ['변수 종류,변수,타입,메모리 할당,초기값,리테인,사용 유무,EIP,OPC UA,HMI,설명문']
        for name, typ in sorted(self.var_declarations.items()):
            comment = self._var_comments.get(name, '')
            lines.append(f'VAR,{name},{typ},,,0,0,0,0,0,{comment}')
        return '\n'.join(lines)


def _safe_name(addr: str) -> str:
    """Convert address to safe ST identifier."""
    return addr.replace('.', '_').replace('#', '_').replace('%', '')

